public class VerzamelGegevens extends AbstractRekenCommand {

    private static final Set<Sleutel<?>> PRESTATIE_VERHOUDING_SLEUTEL;

    static {
        PRESTATIE_VERHOUDING_SLEUTEL = new HashSet<>();
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelRekenWijze.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelPrestatieVerhoudingVorming.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelTellerPrestatieVerhouding.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelNoemerPrestatieVerhouding.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelAanstelling.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelAfwezigheidsCode.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelAfwezigheidsUren.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelMaatman.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelWerkgeversCategorie.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelWerknemersKengetal.INSTANCE);
        PRESTATIE_VERHOUDING_SLEUTEL.add(SleutelAfwezighedenInvoerModule.INSTANCE);
    }

    private static final Set<Looncodegroep> LANGDURIGE_AFWEZIGHEDEN_LOONCODE_GROEPEN = ImmutableSet.of(
            Looncodegroep.ANDERE_LANGDURIGE_AFW,
            Looncodegroep.LOOPBAANVERMINDERING,
            Looncodegroep.VLAAMS_ZORGKREDIET,
            Looncodegroep.THEMATISCH_VERLOF);

    private static final Set<Integer> DMFAPPL_PREST_CODES_LAGE_LOON =
            ImmutableSet.of(PK_DMFA_1.getCode(), PK_DMFA_5.getCode(), PK_DMFA_16.getCode(), PK_DMFA_17.getCode());

    private static final Set<Integer> RSZPPO_PREST_CODE_GEEN_KAND_VERM_LL = ImmutableSet.of(102, 115, 130, 172);

    private static final int RSZPPO_PREST_CODE_KAND_VERM_LL_ONDERGRENS = 100;
    private static final int RSZPPO_PREST_CODE_KAND_VERM_LL_BOVENGRENS = 199;

    private final ConstantManager constantManager;
    private final BasisAardKodeExtensieService basisAardKodeExtensieService;
    private final AardKodeExtensieFacade aardKodeExtensieFacade;
    private UitzonderlijkPerUur uitzonderlijkPerUur;

    public VerzamelGegevens(ConstantManager constantManager, NlpGlobalService service) {
        this.constantManager = constantManager;
        this.aardKodeExtensieFacade = service.getAardKodeExtensieFacade();
        this.basisAardKodeExtensieService = service.getBasisAardKodeExtensieService();
    }

    public VerzamelGegevens(ConstantManager constantManager, NlpGlobalService service, UitzonderlijkPerUur isUitzonderlijkPerUUr) {
        this.constantManager = constantManager;
        this.aardKodeExtensieFacade = service.getAardKodeExtensieFacade();
        this.basisAardKodeExtensieService = service.getBasisAardKodeExtensieService();
        this.uitzonderlijkPerUur = isUitzonderlijkPerUUr;
    }

    @Override
    protected boolean execute(RekenContext context) {
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        RegulManager regulManager = context.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
        Persoon persoon = context.getUnchecked(RekenChainKey.PERSOON_KEY);
        Set<Opdracht> opdrachten = persoon.getOpdrachten();
        RkmCoreHrConfiguratieManager coreHrConfiguratieManager = context.getUnchecked(RekenChainKey.RKM_COREHR_CONFIG_MANAGER);
        uitzonderlijkPerUur = UitzonderlijkPerUurFactory.build(constantManager, aardKodeExtensieFacade, coreHrConfiguratieManager, rekenTijd);
        for (Opdracht opdracht : opdrachten) {
            RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
            bepaalInDienstOfUitdienst(opdrachtContext, opdracht, rekenTijd);
            verzamelGegevens(opdrachtContext, opdracht);
            opdrachtContext.put(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY, RekenTools.getOpperLaatsteGegevens(opdracht));
            bepaalPrestatieVerhoudingen(opdrachtContext, opdracht, regulManager);
        }

        Indexator indexator = new Indexator(constantManager, rekenTijd.eindDatum);
        context.put(RekenChainKey.INDEXATOR_KEY, indexator);

        return CONTINUE_PROCESSING;
    }

    private void bepaalPrestatieVerhoudingen(RekenContext opdrachtContext, Opdracht opdracht, RegulManager regulManager) {
        SleutelSamenNemer aggregator = new SleutelSamenNemer();
        List<SleutelGegevens> aggregaten = aggregator.neemSamenVoorSleutel(opdracht, PRESTATIE_VERHOUDING_SLEUTEL);
        for (SleutelGegevens gegevens : aggregaten) {
            boolean begroting = opdrachtContext.getBoolean(BEGROTING_KEY);
            BigDecimal prestatieVerhouding = RkmPrestatieVerhouding.bepaalTheoretisch(gegevens, regulManager, begroting);
            for (Opper opper : gegevens.getOppers()) {
                opdrachtContext.putDoubleKey(RekenChainKey.PRESTATIEVERHOUDING_KEY, opper, prestatieVerhouding);
            }
        }
    }

    private void bepaalInDienstOfUitdienst(RekenContext opdrachtContext, Opdracht opdracht, RekenTijd rekenTijd) {
        RkmTewerkstelling inDienstOfUitdienst = RkmTewerkstelling.bepaalDoorsnedeTewerkstellingEnRekenPeriode(opdracht, rekenTijd);
        opdrachtContext.put(RekenChainKey.TEWERKSTELLING_AANWEZIG_KEY, inDienstOfUitdienst.isFound());
        if (inDienstOfUitdienst.isFound()) {
            opdrachtContext.put(RekenChainKey.MAAND_TEWERKSTELLING_PERIODE_KEY, inDienstOfUitdienst.getInterval());
        }
        opdrachtContext.put(RekenChainKey.ONVOLLEDIGE_TEWERKSTELLING_KEY, inDienstOfUitdienst.isOnvolledigeTewerkstelling(rekenTijd));
    }

    private void verzamelGegevens(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        PersoonsDataManager dataManager = opdrachtContext.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        UitzPerUurModus uitzPerUurModus = uitzonderlijkPerUur.bepaal(dataManager, opdracht, rekenTijd);

        opdrachtContext.put(RekenChainKey.UITZONDERLIJK_PER_UUR_KEY, uitzPerUurModus);

        for (Opper opper : opdracht.getOpperSlices()) {
            leesPrestaties(opdrachtContext, opper);
        }
        uitzonderlijkPerUur.bepaalTotaalAantalUren(opdrachtContext, opdracht);
        bepaalTotaalWerkDagen(opdrachtContext, opdracht);
    }


    public void bepaalTotaalWerkDagen(RekenContext opdrachtContext, Opdracht opdracht) {
        BigDecimal totaalWerkDagen = BigDecimal.ZERO;
        for (Opper opper : opdracht.getOpperSlices()) {
            PrestatieSamenvattingImp samenvatting = opdrachtContext.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_KEY, opper);
            totaalWerkDagen = totaalWerkDagen.add(samenvatting.getWerkDagen());
        }
        for (Opper opper : opdracht.getOpperSlices()) {
            PrestatieSamenvattingImp samenvatting = opdrachtContext.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_KEY, opper);
            samenvatting.setWerkDagen(totaalWerkDagen);
        }
    }

    public void leesPrestaties(RekenContext context, Opper opper) {
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        RegulManager regulManager = context.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
        PersoonsDataManager dataManager = context.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        LoonCodeManager loonCodeManager = context.getUnchecked(RekenChainKey.LOONCODE_MANAGER_KEY);

        List<NlpPrestatie> prestaties = dataManager.findPrestaties(opper, rekenTijd.eindDatum);

        UitzPerUurModus uitzPerUurModus = context.getUnchecked(RekenChainKey.UITZONDERLIJK_PER_UUR_KEY);
        boolean isUitzonderlijkPerUur = uitzPerUurModus != UitzPerUurModus.GEEN;

        Maandverwerking maandverwerking = opper.getWeddeBerekening().getOmzettingLoonMaandNaarDag();

        boolean bezoldigdePrestatiesAanwezigUitzPerUur =
                uitzonderlijkPerUur.onderzoekBezoldigdePrestatiesAanwezig(opper.getOpdracht(), prestaties, loonCodeManager, uitzPerUurModus);
        LeesPrestatiesResultaat resultaat = new LeesPrestatiesResultaat(uitzonderlijkPerUur, opper.getOpdracht(), bezoldigdePrestatiesAanwezigUitzPerUur);
        boolean overmachtStatutairAanwezig = overmachtStatutairAanwezig(prestaties);

        for (NlpPrestatie prestatie : prestaties) {
            leesPrestatie(resultaat, prestatie, opper, rekenTijd, loonCodeManager, regulManager, isUitzonderlijkPerUur, overmachtStatutairAanwezig);
        }
        PrestatieSamenvattingImp samenvatting = resultaat.getSamenvatting();
        PrestatieSamenvattingUitzPerUur samenvattingUitzPerUur = resultaat.getSamenvattingUitzPerUur();

        if (samenvattingUitzPerUur.getTotaalAantalUren().signum() == 0) {
            samenvattingUitzPerUur.setTotaalAantalUren(samenvattingUitzPerUur.getUitgeslotenUren());
        }
        if (isUitzonderlijkPerUur) {
            samenvattingUitzPerUur.setHwaarde(samenvatting.getHwaarde());
            samenvattingUitzPerUur.setWerkuitkeringUren(samenvatting.getWerkuitkeringUren());
        }

        behandelCaseVariabeleRszDagenVolledigeAfwezigheidInOpper(opper, samenvatting, rekenTijd);

        controleerRegulsamenvatting(samenvatting, opper, rekenTijd, regulManager);
        behandelCaseIndienstOfUitdienstUitzPerUur(context, samenvatting, samenvattingUitzPerUur);
        behandelCaseIndienstOfUitdienstRszDagen(context, maandverwerking, rekenTijd, samenvatting);

        context.putDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_UIT_PER_UUR_KEY, opper, samenvattingUitzPerUur);
        context.putDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_KEY, opper, samenvatting);
        context.putDoubleKey(RekenChainKey.SUPPLEMENTEN_KEY, opper, resultaat.getSupplementen());
        context.putDoubleKey(RekenChainKey.INHOUDINGEN_KEY, opper, resultaat.getInhoudingen());
    }

    private boolean overmachtStatutairAanwezig(List<NlpPrestatie> prestaties) {
        return prestaties.stream().anyMatch(prestatie -> LoonCodeTools.matches(prestatie, CodeExtensie.OVERMACHT_STATUTAIR));
    }

    private void behandelCaseVariabeleRszDagenVolledigeAfwezigheidInOpper(Opper opper, PrestatieSamenvattingImp samenvatting, RekenTijd rekenTijd) {
        Maandverwerking maandverwerking = opper.getWeddeBerekening().getOmzettingLoonMaandNaarDag();
        boolean meerderElementairePeriodes = opper.getOpdracht().getOpperSlices().size() > 1;
        boolean inDienst = opper.getRszppo().getDienstverband() == Dienstverband.JA;
        BigDecimal afwezigheidsUren = bepaalAfwezigheidsUren(opper);
        BigDecimal aanstelling = opper.getRszppo().getAanstelling().subtract(afwezigheidsUren);

        if (aanstelling.signum() == 0 && samenvatting.getTotaalTeller().signum() == 0 && meerderElementairePeriodes &&
                isVariabeleRszOfVlaamseGemeenschap(maandverwerking) && inDienst) {
            BigDecimal theoretischeWerkDagen = samenvatting.getTheoretischeWerkDagen();
            if (theoretischeWerkDagen.signum() == 0) {
                LocalDateInterval periode = opper.getActualInterval().overlap(rekenTijd.rekenPeriode);
                theoretischeWerkDagen = AantalRszDagen.inInterval(periode, 5);
            }
            samenvatting.setWerkDagen(theoretischeWerkDagen);
        }
    }

    private BigDecimal bepaalAfwezigheidsUren(Opper opper) {
        return opper.getAfwezighedenInvoerModule().stream()
                .map(AfwezigheidBO::getHours)
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    private boolean isVariabeleRszOfVlaamseGemeenschap(Maandverwerking maandverwerking) {
        return maandverwerking == Maandverwerking.VLAAMSE_GEMEENSCHAP || maandverwerking == Maandverwerking.VARIABELE_RSZ_DAGEN;
    }

    @Getter
    private static class LeesPrestatiesResultaat {
        private final List<NlpPrestatie> supplementen = new ArrayList<>();
        private final List<NlpPrestatie> inhoudingen = new ArrayList<>();
        private final PrestatieSamenvattingImp samenvatting = new PrestatieSamenvattingImp();
        private final PrestatieSamenvattingUitzPerUur samenvattingUitzPerUur;

        public LeesPrestatiesResultaat(UitzonderlijkPerUur uitzonderlijkPerUur, Opdracht opdracht, boolean bezoldigdePrestatiesAanwezigUitzPerUur) {
            this.samenvattingUitzPerUur = new PrestatieSamenvattingUitzPerUur(uitzonderlijkPerUur, opdracht, bezoldigdePrestatiesAanwezigUitzPerUur);
        }

        public void addSupplement(NlpPrestatie prestatie) {
            supplementen.add(prestatie);
        }

        public void addInhouding(NlpPrestatie prestatie) {
            inhoudingen.add(prestatie);
        }
    }

    private void leesPrestatie(
            LeesPrestatiesResultaat resultaat, NlpPrestatie prestatie, Opper opper, RekenTijd rekenTijd, LoonCodeManager loonCodeManager, RegulManager regulManager,
            boolean isUitzonderlijkPerUur, boolean overmachtStatutairAanwezig) {
        checkTijdperkPrestatie(rekenTijd, opper.getOpdracht(), prestatie, regulManager);

        AardKodeExt aardPrestatie = AardKodeExt.getByCode(prestatie.getAard());
        switch (aardPrestatie) {
            case D_KODE_EXT:
                leesPrestatieDagCode(resultaat, prestatie, opper, loonCodeManager, isUitzonderlijkPerUur, overmachtStatutairAanwezig);
                break;
            case S_KODE_EXT:
                resultaat.addSupplement(prestatie);
                break;
            case I_KODE_EXT:
                resultaat.addInhouding(prestatie);
                break;
            case K_KODE_EXT:
                leesPrestatieKalenderCode(resultaat, prestatie, loonCodeManager, isUitzonderlijkPerUur);
                break;
            default:
                break;
        }

        PrestatieSamenvattingImp samenvatting = resultaat.getSamenvatting();
        if (isKandidaatVerminderingLageLonen(prestatie, rekenTijd)) {
            samenvatting.addToHwaarde(prestatie.getAantal());
        }
        AardKodeExtensie looncode = loonCodeManager.getByPrestatie(prestatie);
        if (komtInAanmerkingVoorWerkuitkering(prestatie, looncode)) {
            samenvatting.addToWerkuitkeringUren(prestatie.getAantal());
        }
    }

    private void leesPrestatieDagCode(
            LeesPrestatiesResultaat resultaat, NlpPrestatie prestatie, Opper opper, LoonCodeManager loonCodeManager, boolean isUitzonderlijkPerUur,
            boolean overmachtStatutairAanwezig) {
        PrestatieSamenvattingImp samenvatting = resultaat.getSamenvatting();
        PrestatieSamenvattingUitzPerUur samenvattingUitzPerUur = resultaat.getSamenvattingUitzPerUur();
        Maandverwerking maandverwerking = opper.getWeddeBerekening().getOmzettingLoonMaandNaarDag();
        AardKodeExtensie looncode = loonCodeManager.getByPrestatie(prestatie);
        if (overmachtStatutairAanwezig && LoonCodeTools.isWeeken80pct(looncode)) {
            looncode = loonCodeManager.getByTake(2, 1, CodeExtensie.OVERMACHT_STATUTAIR.getCode(), CodeExtensie.OVERMACHT_STATUTAIR.getExtensie());
        }
        Tellerkode tellerCode = looncode.getTellerCode();
        if (tellerCode == Tellerkode.DS) {
            resultaat.addSupplement(prestatie);
        } else {
            if (isWerkDag(maandverwerking, looncode)) {
                samenvatting.verwerk(prestatie, looncode);
            }
            if (isUitzonderlijkPerUur && uitzonderlijkPerUur.includerenDagCode(looncode)) {
                samenvattingUitzPerUur.verwerk(prestatie, looncode);
            }
        }
        if (isUitzonderlijkPerUur && !uitzonderlijkPerUur.excluderenInNoemer(looncode.getCode(), looncode.getExtensie())) {
            samenvattingUitzPerUur.addToTotaalAantalUren(prestatie.getAantal());
        }
        samenvatting.addToTotaalAantalUren(prestatie.getAantal());
        if (isWerkDag(maandverwerking, looncode)) {
            samenvatting.addToWerkDagen(prestatie.getX());
        }
        if (isWerkDagTheoretisch(maandverwerking, looncode)) {
            samenvatting.addToTheoretischeWerkDagen(prestatie.getX());
        }
        if (isLangdurigeAfwezigheid(looncode)) {
            samenvatting.addToLangdurigeAfwezigheden(prestatie.getX());
        }
    }

    private void leesPrestatieKalenderCode(
            LeesPrestatiesResultaat resultaat, NlpPrestatie prestatie, LoonCodeManager loonCodeManager, boolean isUitzonderlijkPerUur) {
        AardKodeExtensie looncode = loonCodeManager.getByPrestatie(prestatie);
        PrestatieSamenvattingImp samenvatting = resultaat.getSamenvatting();
        PrestatieSamenvattingUitzPerUur samenvattingUitzPerUur = resultaat.getSamenvattingUitzPerUur();
        if (isUitzonderlijkPerUur) {
            if (!uitzonderlijkPerUur.excluderenInNoemer(looncode.getCode(), looncode.getExtensie())) {
                samenvattingUitzPerUur.addToTotaalAantalUren(prestatie.getAantal());
            } else {
                samenvattingUitzPerUur.addToUitgeslotenUren(prestatie.getAantal());
            }
        }
        samenvatting.addToTotaalAantalUren(prestatie.getAantal());
        if (isUitzonderlijkPerUur && uitzonderlijkPerUur.includerenKalenderCode(looncode)) {
            samenvattingUitzPerUur.verwerk(prestatie, looncode);
        }
    }


    private void behandelCaseIndienstOfUitdienstRszDagen(
            RekenContext context, Maandverwerking maandverwerking, RekenTijd rekenTijd, PrestatieSamenvattingImp samenvatting) {
        boolean indienstOfUitdienst = context.getBoolean(RekenChainKey.ONVOLLEDIGE_TEWERKSTELLING_KEY);
        boolean systeemRszdagen = maandverwerking == Maandverwerking.VARIABELE_RSZ_DAGEN || maandverwerking == Maandverwerking.VLAAMSE_GEMEENSCHAP;
        if (indienstOfUitdienst && systeemRszdagen) {
            boolean tewerkstellingFound = context.getBoolean(RekenChainKey.TEWERKSTELLING_AANWEZIG_KEY);
            LocalDateInterval tewerkstellingMaand = context.getUnchecked(RekenChainKey.MAAND_TEWERKSTELLING_PERIODE_KEY);
            Breuk breuk = getIndienstOfUitdienstRszDagenBreuk(rekenTijd, tewerkstellingFound, tewerkstellingMaand);
            samenvatting.vermenigvuldigMetBreuk(breuk.getTeller(), breuk.getNoemer());
        }
    }

    public Breuk getIndienstOfUitdienstRszDagenBreuk(RekenTijd rekenTijd, boolean tewerkstellingFound, LocalDateInterval tewerkstellingMaand) {
        BigDecimal teller = tewerkstellingFound ? AantalKalenderDagen.inInterval(tewerkstellingMaand) : BigDecimal.ZERO;
        BigDecimal noemer = AantalKalenderDagen.inMaand(rekenTijd.rekenPeriode);
        return new Breuk(teller, noemer);
    }

    private void behandelCaseIndienstOfUitdienstUitzPerUur(
            RekenContext context, PrestatieSamenvattingImp samenvatting, PrestatieSamenvattingUitzPerUur samenvattingUitzPerUur) {
        boolean indienstOfUitdienst = context.getBoolean(RekenChainKey.ONVOLLEDIGE_TEWERKSTELLING_KEY);
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        if (indienstOfUitdienst && !UitzonderlijkPerUur.isAfterStartPlanningsurenConfig(rekenTijd)) {
            Breuk breuk = getIndienstOfUitdienstUitzPerUurBreuk(samenvatting);
            samenvattingUitzPerUur.vermenigvuldigMetBreuk(breuk.getTeller(), breuk.getNoemer());
        }
    }

    public Breuk getIndienstOfUitdienstUitzPerUurBreuk(PrestatieSamenvattingImp samenvatting) {
        return new Breuk(samenvatting.getTotaalTeller(), BigDecimal.valueOf(30));
    }

    private boolean isWerkDag(Maandverwerking maandverwerking, AardKodeExtensie aardKodeExtensie) {
        boolean isGeenWerkdag = !isWerkDagTheoretisch(maandverwerking, aardKodeExtensie);
        if (maandverwerking == Maandverwerking.VLAAMSE_GEMEENSCHAP) {
            isGeenWerkdag = isGeenWerkdag || isLangdurigeAfwezigheid(aardKodeExtensie);
        }
        return !isGeenWerkdag && aardKodeExtensie.getTellerCode() != Tellerkode.DS;
    }

    private boolean isWerkDagTheoretisch(Maandverwerking maandverwerking, AardKodeExtensie aardKodeExtensie) {
        boolean isGeenWerkdag = false;
        if (isVariabeleRszOfVlaamseGemeenschap(maandverwerking)) {
            isGeenWerkdag = isWeekend(aardKodeExtensie) || isNietGewerkt(aardKodeExtensie);
        }
        return !isGeenWerkdag && aardKodeExtensie.getTellerCode() != Tellerkode.DS;
    }

    private boolean isNietGewerkt(AardKodeExtensie aardKodeExtensie) {
        Set<AardKodeExtensie> nietGewerkt = basisAardKodeExtensieService.findAfgeleideLooncodesByBasisAardKodeExtensie(AardKodeExt.D_KODE_EXT.getCode(),
                CodeExtensie.NIET_GEWERKT_WERKROOSTER.getCode(), CodeExtensie.NIET_GEWERKT_WERKROOSTER.getExtensie());
        return nietGewerkt.contains(aardKodeExtensie);
    }

    private boolean isWeekend(AardKodeExtensie aardKodeExtensie) {
        Set<AardKodeExtensie> weekends =
                basisAardKodeExtensieService.findAfgeleideLooncodesByBasisAardKodeExtensie(AardKodeExt.D_KODE_EXT.getCode(), CodeExtensie.WEEKEND.getCode(),
                        CodeExtensie.WEEKEND.getExtensie());
        return weekends.contains(aardKodeExtensie);
    }

    private boolean isLangdurigeAfwezigheid(AardKodeExtensie aardKodeExtensie) {
        Set<AardKodeExtensie> langdurigeAfwezigheden = basisAardKodeExtensieService.findAfgeleideLooncodesByLooncodeGroepen(LANGDURIGE_AFWEZIGHEDEN_LOONCODE_GROEPEN);
        return langdurigeAfwezigheden.contains(aardKodeExtensie);
    }

    private void controleerRegulsamenvatting(PrestatieSamenvattingImp samenvatting, Opper opper, RekenTijd rekenTijd, RegulManager regulManager) {
        boolean vastbenoemd = RekenTools.isVastbenoemd(opper, rekenTijd);
        boolean heeftDispo = samenvatting.getTellerDisponibiliteit60().signum() != 0 || samenvatting.getTellerDisponibiliteit100().signum() != 0;
        boolean heeftZiek234 = samenvatting.getTellerZiekteDerdeEnVierdeWeek().signum() != 0 || samenvatting.getTellerZiekteTweedeWeek().signum() != 0;
        boolean heeftEnkelT1 = samenvatting.getTellerGewoneBezoldiging().compareTo(samenvatting.getTotaalTeller()) == 0;
        Integer afwezigheidsCode = opper.getRszppo().getAfwezigheidsCode();

        if ((afwezigheidsCode == 180 && !heeftEnkelT1)
                || (vastbenoemd && heeftZiek234) || (!vastbenoemd && heeftDispo)
                || (afwezigheidsCode == 171 && RekenTools.getTijdperk(rekenTijd) == AkeTijdperk.RSZPPO && heeftDispo)) {
            regulManager.doRegulException(opper.getOpdracht(), Regulkode.ONGELDIGE_TELLER_VOOR_KATEGORIE);
        }
        if (tellerStatutairToegekendAanNietStatutair(samenvatting, vastbenoemd)) {
            regulManager.doRegulException(opper.getOpdracht(), Regulkode.COMBINATIE_NIET_STATUTAIR_EN_TELLER_VERBODEN);
        }
    }

    private boolean tellerStatutairToegekendAanNietStatutair(PrestatieSamenvattingImp samenvatting, boolean vastbenoemd) {
        boolean nietStatutair = !vastbenoemd;
        boolean statutaireTellers = samenvatting.getTellerBetaling82().signum() != 0 ||
                samenvatting.getTellerBetaling80().signum() != 0 ||
                samenvatting.getTellerGeboorteVerlof().signum() != 0 || samenvatting.getTellerBetalingOvermacht().signum() != 0;
        return nietStatutair && statutaireTellers;
    }

    private void checkTijdperkPrestatie(RekenTijd rekenTijd, Opdracht opdracht, NlpPrestatie prestatie, RegulManager regulManager) {
        AkeTijdperk huidigTijdperk = RekenTools.getTijdperk(rekenTijd);
        AkeTijdperk tijdperk = AkeTijdperk.getByCode(prestatie.getTijdperk());
        AardKodeExt aard = AardKodeExt.getByCode(prestatie.getAard());
        if ((RekenTools.AARD_MET_TP_BEIDE.contains(aard) && tijdperk != AkeTijdperk.BEIDE)
                || (RekenTools.AARD_MET_TIJDAFHANKELIJKE_TP.contains(aard) && huidigTijdperk != tijdperk)) {
            regulManager.doRegulException(opdracht, Regulkode.TP_ONGELDIG);
        }
    }

    private boolean komtInAanmerkingVoorWerkuitkering(NlpPrestatie prestatie, AardKodeExtensie looncode) {
        Integer prestatieCode = prestatie.getPrestatieCode();
        Tellerkode tellerCode = looncode.getTellerCode();
        return prestatieCode == 1 || (prestatieCode == 10 && tellerCode == Tellerkode.Z2);
    }

    private boolean isKandidaatVerminderingLageLonen(NlpPrestatie prestatie, RekenTijd rekenTijd) {
        Integer prestatieCode = prestatie.getPrestatieCode();
        boolean isKandidaat;
        switch (RekenTools.getTijdperk(rekenTijd)) {
            case RSZPPO:
                isKandidaat = prestatieCode >= RSZPPO_PREST_CODE_KAND_VERM_LL_ONDERGRENS && prestatieCode <= RSZPPO_PREST_CODE_KAND_VERM_LL_BOVENGRENS
                        && !RSZPPO_PREST_CODE_GEEN_KAND_VERM_LL.contains(prestatieCode);
                break;
            case DMFAPPL:
            default:
                isKandidaat = DMFAPPL_PREST_CODES_LAGE_LOON.contains(prestatieCode);
                break;
        }
        return isKandidaat;
    }

